package main

import (
	"sort"
)

func solve(nums []int64) int64 {
	n := len(nums)
	if n < 2 {
		return 0
	}
	abs := make([]int64, n)
	for i := 0; i < n; i++ {
		abs[i] = int64(abs(int64(nums[i])))
	}
	sort.Sort(sort.Int64Slice(abs))
	count := int64(0)
	for i := 0; i < n-1; i++ {
		target := 2 * abs[i]
		left := i + 1
		right := n - 1
		res := i
		for left <= right {
			mid := (left + right) / 2
			if abs[mid] <= target {
				res = mid
				left = mid + 1
			} else {
				right = mid - 1
			}
		}
		count += int64(res - i)
	}
	return count
}
